### Basic Test

```jac
test "my feature" {
    # Test body
    assert condition;
}
```

### Test with Setup

```jac
obj MyObject {
    has data: str;

    def process() -> str {
        return self.data;
    }
}

test "object processing" {
    # Setup
    my_obj = MyObject(data="test");

    # Test
    result = my_obj.process();

    # Assert
    assert result == "test";
}
```

### Basic Assert

```jac
test "basic assert" {
    assert condition;
    assert condition, "Error message";
}
```

### Boolean

```jac
test "boolean values" {
    assert True;
    assert not False;
    assert bool(value);
}
```

### Membership

```jac
test "membership" {
    assert item in collection;
    assert item not in collection;
    assert key in dictionary;
}
```

### Type Checking

```jac
test "type checking" {
    assert isinstance(obj, MyClass);
    assert type(obj) == MyClass;
}
```

### None Checking

```jac
test "none checking" {
    assert value is None;
    assert value is not None;
}
```

```jac
test "float comparison" {
    result = 0.1 + 0.2;
    assert abs(result - 0.3) < 1e-10;
}
```

### With Messages

```jac
test "assertions with messages" {
    assert result > 0, f"Expected positive, got {result}";
    assert len(items) == 3, "Should have 3 items";
}
```
